message.content:
{
  "diagnosis": {
    "what_is_working": [
      "La interfaz es clara en mostrar el progreso del expediente con un indicador de fortaleza simple y no gamificado, lo que evita presión innecesaria.",
      "Las sugerencias de próximos documentos son útiles y contextuales, basadas en tipos reales de documentos laborales mexicanos.",
      "Se separa visualmente el estado de procesamiento y se proporciona retroalimentación inmediata después de subir un documento, fomentando confianza."
    ],
    "what_is_confusing": [
      "La pantalla está sobrecargada con secciones laterales y principales que compiten por atención, lo que puede abrumar a usuarios no técnicos al no priorizar jerárquicamente la información crítica como datos confirmados vs. estimados.",
      "Los detalles técnicos como 'SHA-256' o 'confianza %' aparecen en el historial, introduciendo jerga que no es necesaria para el usuario final.",
      "No hay una separación clara entre datos confirmados y estimados en los resultados de procesamiento, lo que podría generar expectativas irreales."
    ],
    "highest_risk_for_user_trust": [
      "Mostrar estimaciones sin diferenciarlas claramente de lo confirmado podría llevar a malentendidos, haciendo que el usuario crea que el análisis es definitivo cuando no lo es.",
      "La falta de énfasis en la trazabilidad y seguridad podría generar ansiedad sobre la privacidad de documentos sensibles laborales.",
      "Sugerencias de próximos pasos que suenan como obligaciones podrían percibirse como presión, erosionando la sensación de control y simplicidad."
    ]
  },
  "recommended_information_hierarchy": [
    {
      "order": 1,
      "section": "Resumen del expediente actual",
      "why": "Debe ser lo primero para que el usuario entienda inmediatamente el estado general, reduciendo ansiedad al mostrar progreso confirmado y estimado de manera honesta."
    },
    {
      "order": 2,
      "section": "Último documento subido y su aporte",
      "why": "Proporciona retroalimentación inmediata sobre la acción reciente, separando lo confirmado de lo estimado para mantener la honestidad y guiar al siguiente paso sin promesas exageradas."
    },
    {
      "order": 3,
      "section": "Formulario de subida de documento",
      "why": "Facilita la acción principal de forma simple, con pistas claras para no técnicos, posicionada después del contexto para que el usuario suba con comprensión."
    },
    {
      "order": 4,
      "section": "Historial de documentos",
      "why": "Ofrece trazabilidad al final, como referencia, sin abrumar, enfocándose en aportes útiles en lugar de detalles técnicos."
    },
    {
      "order": 5,
      "section": "Sugerencia de siguiente paso",
      "why": "Cierra el flujo con una guía suave y no prescriptiva, basada en el expediente actual, para sentir utilidad sin generar ansiedad."
    }
  ],
  "recommended_core_cards": [
    {
      "name": "Tarjeta de Resumen de Expediente",
      "purpose": "Mostrar la fortaleza general del expediente, separando cobertura confirmada de estimada, para dar una visión honesta y tranquilizadora.",
      "must_show": [
        "Porcentaje de cobertura útil (basado en tipos de documentos presentes)",
        "Etiquetas simples como 'Base sólida' o 'En crecimiento'",
        "Separación clara: 'Documentos confirmados' vs. 'Estimaciones preliminares'"
      ],
      "must_not_show": [
        "Barras de progreso gamificadas o colores que impliquen urgencia",
        "Cualquier mención a análisis legales definitivos"
      ]
    },
    {
      "name": "Tarjeta de Último Documento",
      "purpose": "Explicar qué se subió, su aporte confirmado y estimado, y estado de procesamiento, para reforzar confianza en la utilidad del producto.",
      "must_show": [
        "Nombre del documento y tipo clasificado",
        "Aporte: 'Esto confirma...' vs. 'Esto estima...'",
        "Estado de procesamiento con iconos simples (e.g., check para enviado)"
      ],
      "must_not_show": [
        "Detalles técnicos como hashes o porcentajes de confianza",
        "Sugerencias que suenen como promesas de resultados"
      ]
    },
    {
      "name": "Tarjeta de Sugerencia",
      "purpose": "Guiar al siguiente paso útil sin presión, basado en el expediente actual, para que el usuario se sienta apoyado.",
      "must_show": [
        "Sugerencia suave: 'Un documento como [tipo] podría ayudar a aclarar...'",
        "Razones simples y beneficios laborales reales"
      ],
      "must_not_show": [
        "Llamados a acción urgentes o contadores de 'falta'",
        "Cualquier implicación de que sea obligatorio"
      ]
    }
  ],
  "copy_principles": [
    "Usar lenguaje cotidiano mexicano, simple y empático, como 'Esto ayuda a ver mejor...' en lugar de términos técnicos.",
    "Siempre separar 'confirmado' (basado en datos verificados) de 'estimado' (preliminar de IA) con palabras claras y honestas.",
    "Evitar promesas: no decir 'resolverá tu caso', sino 'puede dar más contexto para entender tu situación'.",
    "Minimizar ansiedad con frases tranquilizadoras como 'Tu documento está seguro y trazado'.",
    "Ser breve: oraciones cortas, listas simples, nada de párrafos densos."
  ],
  "microcopy_examples": {
    "confirmed_data_title": "Datos confirmados del documento",
    "estimated_data_title": "Estimaciones preliminares (aún no verificadas)",
    "next_step_title": "Qué podría ayudar después",
    "processing_state_sent": "Documento enviado y en revisión segura.",
    "processing_state_pending": "Guardado, pero la revisión automática está pendiente; lo revisaremos pronto.",
    "empty_state": "Empieza subiendo tu primer documento, como un recibo de nómina, para ver cómo fortalece tu expediente."
  },
  "interaction_recommendations": [
    "Usar un flujo progresivo: después de subir, mostrar inmediatamente la tarjeta de último documento con animación suave para retroalimentación positiva.",
    "Incluir botones grandes y claros, como 'Subir documento' con icono, y un 'Limpiar' secundario, para simplicidad en móviles.",
    "Agregar tooltips no intrusivos en términos como 'CFDI' explicando 'Comprobante Fiscal Digital por Internet' solo si se hoverea.",
    "Permitir refrescar el estado con un botón visible, pero con mensaje 'Actualizando...' para evitar clics repetidos.",
    "Asegurar que selecciones de expediente y caso sean dropdowns con etiquetas descriptivas, precargando el más reciente para reducir pasos."
  ],
  "visual_tone": {
    "overall": "Simple y confiable, con tonos suaves de verde y azul para transmitir seguridad y calma, como un expediente organizado y accesible.",
    "avoid": [
      "Colores rojos o amarillos que sugieran alerta o error, a menos que sea un fallo real",
      "Elementos gamificados como badges o estrellas",
      "Diseños densos con muchas tarjetas; priorizar espacio blanco"
    ],
    "emphasis": [
      "Iconos simples (e.g., candado para seguridad) en verde para elementos confirmados",
      "Texto en negrita para separadores como 'Confirmado' vs. 'Estimado'",
      "Bordes suaves y redondeados para todas las tarjetas, evocando accesibilidad"
    ]
  },
  "one_sentence_direction": "Rediseña la interfaz para priorizar una jerarquía clara que separe lo confirmado de lo estimado, con tarjetas simples que guíen al usuario de manera honesta y tranquilizadora hacia un expediente laboral más fuerte."
}
